namespace sv_e922f533e90d4a56937c36db9bb86422.Services;

public class AppointmentService
{
    public Task<List<string>> GetDoctorsAsync()
    {
        var doctors = new List<string>
        {
            "Dr. Smith",
            "Dr. Johnson",
            "Dr. Patel",
            "Dr. Williams"
        };
        return Task.FromResult(doctors);
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        var slots = new List<string>
        {
            "9:00 AM",
            "10:00 AM",
            "11:00 AM",
            "1:00 PM",
            "2:00 PM",
            "3:00 PM"
        };
        return Task.FromResult(slots);
    }

    /// <summary>
    /// Validates patient and appointment details server-side.
    /// Returns a dictionary of field name -> error message for any validation failures.
    /// </summary>
    public Task<Dictionary<string, string>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, string>();

        // Simulate outstanding balance check
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors["Email"] = "Account has outstanding balance";
        }

        // Simulate self-pay rejection for Dr. Smith
        if (insuranceProvider == "None" && doctor == "Dr. Smith")
        {
            errors["Doctor"] = "Selected doctor does not accept self-pay patients";
        }

        // Simulate race condition on time slot
        if (timeSlot == "10:00 AM")
        {
            errors["TimeSlot"] = "This slot is no longer available";
        }

        return Task.FromResult(errors);
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_e922f533e90d4a56937c36db9bb86422.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h1>Book a Medical Appointment</h1>

<EditForm Model="@Model" OnValidSubmit="HandleSubmitAsync">
    <DataAnnotationsValidator />

    @* STEP 1 *@
    <fieldset>
        <legend>Step 1: Patient Information</legend>

        <div class="mb-3">
            <label for="patientName" class="form-label">Patient Name</label>
            <InputText id="patientName" class="form-control" @bind-Value="Model.PatientName" />
            <ValidationMessage For="@(() => Model.PatientName)" />
        </div>

        <div class="mb-3">
            <label for="email" class="form-label">Email</label>
            <InputText id="email" class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="@(() => Model.Email)" />
            @if (_serverErrors.ContainsKey("Email"))
            {
                <div class="validation-message">@_serverErrors["Email"]</div>
            }
        </div>

        <div class="mb-3">
            <label for="phone" class="form-label">Phone</label>
            <InputText id="phone" class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="@(() => Model.Phone)" />
        </div>

        <div class="mb-3">
            <label for="insurance" class="form-label">Insurance Provider</label>
            <InputSelect id="insurance" class="form-control" @bind-Value="Model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="@(() => Model.InsuranceProvider)" />
        </div>
    </fieldset>

    @if (!_showStep2)
    {
        <button type="button" class="btn btn-primary mt-3" @onclick="ProceedToStep2Async">
            Next: Choose Appointment
        </button>
    }

    @* STEP 2 *@
    @if (_showStep2)
    {
        <fieldset class="mt-4">
            <legend>Step 2: Appointment Details</legend>

            <div class="mb-3">
                <label for="doctor" class="form-label">Preferred Doctor</label>
                <InputSelect id="doctor" class="form-control" @bind-Value="Model.Doctor" ValueChanged="OnDoctorChanged" ValueExpression="@(() => Model.Doctor)">
                    <option value="">-- Select --</option>
                    @foreach (var doc in _doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="@(() => Model.Doctor)" />
                @if (_serverErrors.ContainsKey("Doctor"))
                {
                    <div class="validation-message">@_serverErrors["Doctor"]</div>
                }
            </div>

            <div class="mb-3">
                <label for="date" class="form-label">Date</label>
                <InputDate id="date" class="form-control" @bind-Value="Model.AppointmentDate" />
                <ValidationMessage For="@(() => Model.AppointmentDate)" />
            </div>

            <div class="mb-3">
                <label for="timeslot" class="form-label">Time Slot</label>
                <InputSelect id="timeslot" class="form-control" @bind-Value="Model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in _timeSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="@(() => Model.TimeSlot)" />
                @if (_serverErrors.ContainsKey("TimeSlot"))
                {
                    <div class="validation-message">@_serverErrors["TimeSlot"]</div>
                }
            </div>

            <div class="mb-3">
                <label for="reason" class="form-label">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" @bind-Value="Model.ReasonForVisit" />
                <ValidationMessage For="@(() => Model.ReasonForVisit)" />
            </div>

            <button type="button" class="btn btn-secondary mt-3" @onclick="CheckAvailabilityAsync">
                Check Availability
            </button>

            @if (_availabilityConfirmed)
            {
                <button type="submit" class="btn btn-success mt-3 ms-2">
                    Confirm Appointment
                </button>
            }
        </fieldset>
    }
</EditForm>

@if (_submitted)
{
    <div class="alert alert-success mt-4">
        Appointment booked successfully!
    </div>
}

@code {
    private AppointmentModel Model { get; set; } = new();
    private List<string> _doctors = new();
    private List<string> _timeSlots = new();
    private Dictionary<string, string> _serverErrors = new();
    private bool _showStep2;
    private bool _availabilityConfirmed;
    private bool _submitted;
    private EditContext? _editContext;

    protected override async Task OnInitializedAsync()
    {
        _doctors = await AppointmentService.GetDoctorsAsync();
    }

    private async Task ProceedToStep2Async()
    {
        _serverErrors.Clear();
        _editContext = new EditContext(Model);
        var validationMessageStore = new ValidationMessageStore(_editContext);

        // Validate step 1 fields manually
        var isValid = true;

        if (string.IsNullOrWhiteSpace(Model.PatientName))
            isValid = false;
        if (string.IsNullOrWhiteSpace(Model.Email) || !Model.Email.Contains('@'))
            isValid = false;
        if (string.IsNullOrWhiteSpace(Model.Phone))
            isValid = false;
        if (string.IsNullOrWhiteSpace(Model.InsuranceProvider))
            isValid = false;

        // Use DataAnnotations validation
        var validationContext = new System.ComponentModel.DataAnnotations.ValidationContext(Model);
        var results = new List<System.ComponentModel.DataAnnotations.ValidationResult>();
        System.ComponentModel.DataAnnotations.Validator.TryValidateProperty(
            Model.PatientName,
            new System.ComponentModel.DataAnnotations.ValidationContext(Model) { MemberName = nameof(Model.PatientName) },
            results);
        System.ComponentModel.DataAnnotations.Validator.TryValidateProperty(
            Model.Email,
            new System.ComponentModel.DataAnnotations.ValidationContext(Model) { MemberName = nameof(Model.Email) },
            results);
        System.ComponentModel.DataAnnotations.Validator.TryValidateProperty(
            Model.Phone,
            new System.ComponentModel.DataAnnotations.ValidationContext(Model) { MemberName = nameof(Model.Phone) },
            results);
        System.ComponentModel.DataAnnotations.Validator.TryValidateProperty(
            Model.InsuranceProvider,
            new System.ComponentModel.DataAnnotations.ValidationContext(Model) { MemberName = nameof(Model.InsuranceProvider) },
            results);

        if (results.Count == 0)
        {
            _showStep2 = true;
        }
    }

    private async Task OnDoctorChanged(string value)
    {
        Model.Doctor = value;
        _serverErrors.Remove("Doctor");
        await LoadTimeSlotsAsync();
    }

    private async Task LoadTimeSlotsAsync()
    {
        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate != default)
        {
            _timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                Model.Doctor, Model.AppointmentDate);
        }
        else if (!string.IsNullOrEmpty(Model.Doctor))
        {
            // Load with today+1 as default to show slots
            _timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                Model.Doctor, DateOnly.FromDateTime(DateTime.Today.AddDays(1)));
        }
        else
        {
            _timeSlots = new();
        }
    }

    private async Task CheckAvailabilityAsync()
    {
        _serverErrors.Clear();
        _availabilityConfirmed = false;

        // Client-side validation for step 2 fields
        var results = new List<System.ComponentModel.DataAnnotations.ValidationResult>();
        var isStep2Valid = System.ComponentModel.DataAnnotations.Validator.TryValidateObject(
            Model, new System.ComponentModel.DataAnnotations.ValidationContext(Model), results, true);

        if (!isStep2Valid)
        {
            return;
        }

        // Server-side validation
        var errors = await AppointmentService.ValidatePatientAsync(
            Model.Email,
            Model.InsuranceProvider,
            Model.Doctor,
            Model.TimeSlot);

        if (errors.Count > 0)
        {
            _serverErrors = errors;
        }
        else
        {
            _availabilityConfirmed = true;
        }
    }

    private async Task HandleSubmitAsync()
    {
        _submitted = true;
    }

    public class AppointmentModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Patient name is required")]
        public string PatientName { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Email is required")]
        [System.ComponentModel.DataAnnotations.EmailAddress(ErrorMessage = "Invalid email format")]
        public string Email { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Phone is required")]
        public string Phone { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Insurance provider is required")]
        public string InsuranceProvider { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Doctor is required")]
        public string Doctor { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Date is required")]
        [FutureDate(ErrorMessage = "Date must be in the future")]
        public DateOnly AppointmentDate { get; set; } = DateOnly.FromDateTime(DateTime.Today.AddDays(1));

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Time slot is required")]
        public string TimeSlot { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Reason for visit is required")]
        [System.ComponentModel.DataAnnotations.MaxLength(500, ErrorMessage = "Reason cannot exceed 500 characters")]
        public string ReasonForVisit { get; set; } = "";
    }

    public class FutureDateAttribute : System.ComponentModel.DataAnnotations.ValidationAttribute
    {
        protected override System.ComponentModel.DataAnnotations.ValidationResult? IsValid(
            object? value, System.ComponentModel.DataAnnotations.ValidationContext validationContext)
        {
            if (value is DateOnly date && date <= DateOnly.FromDateTime(DateTime.Today))
            {
                return new System.ComponentModel.DataAnnotations.ValidationResult(ErrorMessage);
            }
            return System.ComponentModel.DataAnnotations.ValidationResult.Success;
        }
    }
}

